459→function printHeader(): void {
460→  println();
461→  println('==========================================', 'blue');
462→  println('   Ralph Loop - Bun.js Edition', 'blue');
463→  println('==========================================', 'blue');
464→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
465→  println(`Log dir:        ${chalk.yellow(LOG_DIR)}`);
466→  println(
467→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
468→  );
469→  println(
470→    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
471→  );
472→  println();
473→}
474→
475→async function main(): Promise<void> {
476→  let cleanupCalled = false;
477→
478→  const cleanup = (signal: string) => {
479→    if (cleanupCalled) return;
480→    cleanupCalled = true;
481→    println();
482→    syslog(`Interrupted by ${signal}. Cleaning up...`);
483→    killCurrentProc();
484→    logBuffer.dispose();
485→    process.exit(signal === 'SIGINT' ? 130 : 143);
486→  };
487→
488→  process.on('SIGINT', () => cleanup('SIGINT'));
489→  process.on('SIGTERM', () => cleanup('SIGTERM'));
490→
491→  await checkDependencies();
492→
493→  printHeader();
494→  syslog('Starting automated task loop...');
495→
496→  let consecutiveFailures = 0;
497→  let iteration = 0;
498→  const BACKOFF_BASE_MS = 30_000;
499→  const BACKOFF_MAX_MS = 30 * 60_000;
500→
501→  while (iteration < CONFIG.maxIterations) {
502→    const attemptNum = iteration + 1;
503→    logBuffer.startNewFile(logFilePath(`iter-${attemptNum}`));
504→
505→    println();
506→    println('==========================================', 'green');
507→    syslog(`Iteration #${attemptNum} / ${CONFIG.maxIterations}`, 'green');
508→    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
509→    println('==========================================', 'green');
510→    println();
511→
512→    const { output, exitCode, timedOut } = await runIteration();
513→
514→    if (exitCode === 0) {
515→      syslog('Claude Code completed successfully', 'green');
516→      consecutiveFailures = 0;
517→    } else if (timedOut) {
518→      syslog(
519→        'Iteration timed out — progress may persist in progress.txt',
520→        'yellow',
521→      );
522→      consecutiveFailures = 0;
523→    } else {
524→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
525→      consecutiveFailures++;
526→
527→      const backoffMs = Math.min(
528→        BACKOFF_BASE_MS * Math.pow(2, consecutiveFailures - 1),
529→        BACKOFF_MAX_MS,
530→      );
531→      const backoffMin = (backoffMs / 60_000).toFixed(1);
532→
533→      println();
534→      println('==========================================', 'yellow');
535→      syslog(
536→        `${consecutiveFailures} consecutive failure(s) — retrying in ${backoffMin}min`,
537→        'yellow',
538→      );
539→      println('==========================================', 'yellow');
540→
541→      await Bun.sleep(backoffMs);
542→      continue;
543→    }
544→
545→    iteration++;
546→
547→    const status = parseRalphStatus(output);
548→    const taskSlug = status
549→      ? slugify(status.task)
550→      : timedOut
551→        ? 'timeout'
552→        : 'no-status';
553→    logBuffer.renameFile(logFilePath(taskSlug));
554→
555→    if (status?.exit) {
556→      println();
557→      println('==========================================', 'green');
558→      syslog('ALL TASKS COMPLETED!', 'green');
559→      syslog(`Final task:      ${status.task}`, 'green');
560→      syslog(`Remaining:       ${status.remaining}`, 'green');
561→      syslog(`Total iterations: ${iteration}`, 'green');
562→      println('==========================================', 'green');
563→      logBuffer.dispose();
564→      process.exit(0);
565→    }
566→
567→    if (status) {
568→      syslog(
569→        `Task done: "${status.task}" — ${status.remaining} remaining`,
570→        'blue',
571→      );
572→    } else if (!timedOut && exitCode === 0) {
573→      syslog(
574→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
575→        'yellow',
576→      );
577→    }
578→
579→    if (iteration < CONFIG.maxIterations) {
580→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
581→      println();
582→      syslog(`Waiting ${delaySec}s before next iteration...`);
583→      await Bun.sleep(CONFIG.delayBetweenIterations);
584→    }
585→  }
586→
587→  println();
588→  println('==========================================', 'red');
589→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
590→  syslog('Loop stopped — tasks may still be pending', 'red');
591→  println('==========================================', 'red');
592→  logBuffer.dispose();
593→  process.exit(1);
594→}
595→
596→main();
